+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type WindowValue<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+
+type WindowOrder = SQLWrapper;
+
+type FrameBoundaryKind = 'unbounded preceding' | 'preceding' | 'current row' | 'following' | 'unbounded following';
+
+export interface WindowFrameBoundary {
+	readonly kind: FrameBoundaryKind;
+	readonly value?: number;
+}
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: WindowFrameBoundary;
+	readonly to: WindowFrameBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: WindowOrder | WindowOrder[];
+	orderBy?: WindowOrder | WindowOrder[];
+	frame?: WindowFrame;
+}
+
+export const unboundedPreceding: WindowFrameBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowFrameBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowFrameBoundary = { kind: 'unbounded following' };
+
+function positionalBoundary(name: 'preceding' | 'following', value: number): WindowFrameBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+	return { kind: name, value };
+}
+
+export function preceding(value: number): WindowFrameBoundary {
+	return positionalBoundary('preceding', value);
+}
+
+export function following(value: number): WindowFrameBoundary {
+	return positionalBoundary('following', value);
+}
+
+function boundaryOrder(boundary: WindowFrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return 0;
+		case 'preceding': return 1;
+		case 'current row': return 2;
+		case 'following': return 3;
+		case 'unbounded following': return 4;
+	}
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be after the "to" boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+function buildBoundary(boundary: WindowFrameBoundary): SQL {
+	return boundary.value === undefined ? sql.raw(boundary.kind) : sql`${sql.raw(String(boundary.value))} ${sql.raw(boundary.kind)}`;
+}
+
+/** @internal */
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+	const orderBy = spec.orderBy === undefined ? [] : (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+	const frameSql = spec.frame
+		? sql` ${sql.raw(spec.frame.type)} between ${buildBoundary(spec.frame.from)} and ${buildBoundary(spec.frame.to)}`
+		: undefined;
+	return sql`${partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined}${orderBy.length ? sql` order by ${sql.join(orderBy, sql`, `)}` : undefined}${frameSql}`;
+}
+
+class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(specOrName: WindowSpec | string): SQL<T> {
+		return typeof specOrName === 'string'
+			? sql`${this.expression} over ${sql.identifier(specOrName)}`
+			: sql`${this.expression} over (${buildWindowSpec(specOrName)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positionalArgument(name: 'ntile' | 'nthValue', value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer, received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function ntile(buckets: number): WindowFunction<number> { return windowFunction('ntile', [positionalArgument('ntile', buckets)]); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<WindowValue<T> | null>;
