+export function lag<T extends SQLWrapper, TDefault>(expression: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<WindowValue<T> | TDefault>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: unknown): WindowFunction<WindowValue<T> | null> {
