+import { expect, test } from 'vitest';
+
+import { PgDialect, pgTable, text } from '~/pg-core/index.ts';
+import {
+	cumeDist,
+	currentRow,
+	denseRank,
+	following,
+	lag,
+	ntile,
+	percentRank,
+	preceding,
+	range,
+	rank,
+	rowNumber,
+	rows,
+	unboundedPreceding,
+	windowCount,
+	windowSum,
+} from '~/sql/functions/index.ts';
+import { PgSelectBuilder } from '~/pg-core/query-builders/select.ts';
+
+const users = pgTable('users', { name: text('name') });
+const dialect = new PgDialect();
+
+function query(expression: ReturnType<typeof rowNumber>['over']) {
+	return dialect.sqlToQuery(expression({})).sql;
+}
+
+test('window functions use inline positional arguments and window specs', () => {
+	const frame = rows({ from: unboundedPreceding, to: currentRow });
+	expect(dialect.sqlToQuery(rowNumber().over({ partitionBy: users.name, orderBy: users.name, frame }))).toEqual({
+		sql: 'row_number() over (partition by "users"."name" order by "users"."name" rows between unbounded preceding and current row)',
+		params: [],
+	});
+	expect(dialect.sqlToQuery(ntile(4).over({}))).toEqual({ sql: 'ntile(4) over ()', params: [] });
+	expect(dialect.sqlToQuery(lag(users.name, 0).over({}))).toEqual({ sql: 'lag("users"."name", 0) over ()', params: [] });
+	expect(dialect.sqlToQuery(windowCount().over({}))).toEqual({ sql: 'count(*) over ()', params: [] });
+	expect(dialect.sqlToQuery(windowSum(users.name).over('totals'))).toEqual({ sql: 'sum("users"."name") over "totals"', params: [] });
+	for (const expression of [rank(), denseRank(), percentRank(), cumeDist()]) {
+		expect(dialect.sqlToQuery(expression.over({})).params).toEqual([]);
+	}
+});
+
+test('named windows compile before order by and names are validated', () => {
+	const builder = new PgSelectBuilder({ fields: { number: rowNumber().over('ranked') }, dialect, session: undefined });
+	const built = builder.from(users).window('ranked', { orderBy: users.name }).orderBy(users.name);
+	expect(dialect.sqlToQuery(built.getSQL())).toEqual({
+		sql: 'select row_number() over "ranked" from "users" window "ranked" as (order by "users"."name") order by "users"."name"',
+		params: [],
+	});
+	expect(() => built.window('', {})).toThrow('non-empty');
+	expect(() => built.window('  ', {})).toThrow('whitespace');
+});
+
+test('frame and positional arguments validate their bounds', () => {
+	expect(() => ntile(0)).toThrow('ntile');
+	expect(() => preceding(-1)).toThrow('preceding');
+	expect(() => following(1.5)).toThrow('following');
+	expect(() => range({ from: following(1), to: currentRow })).toThrow('from');
+});
